// ===== NEW: Get enriched context from agentic workflow =====
const enrichedContext = $input.first().json.enriched_context || {};
const pastPosts = $('Get Past Successful Posts').all() || [];

let learningContext = "";

// Add system instructions from agentic workflow
if (enrichedContext.system_instructions) {
  learningContext += "\n=== SYSTEM GUIDELINES ===\n";
  learningContext += enrichedContext.system_instructions + "\n\n";
}

// Add conversation context
if (enrichedContext.conversation_summary) {
  learningContext += "\n=== RECENT CONTEXT ===\n";
  learningContext += enrichedContext.conversation_summary + "\n\n";
}

// Add RAG knowledge
if (enrichedContext.relevant_knowledge) {
  learningContext += "\n=== BRAND & MEDICAL KNOWLEDGE ===\n";
  learningContext += enrichedContext.relevant_knowledge + "\n\n";
}

// Add execution plan
if (enrichedContext.execution_plan) {
  learningContext += "\n=== EXECUTION PLAN ===\n";
  learningContext += `Complexity: ${enrichedContext.execution_plan.complexity || 'N/A'}\n`;
  learningContext += `Steps: ${enrichedContext.execution_plan.steps ? enrichedContext.execution_plan.steps.join(' → ') : 'N/A'}\n\n`;
}

// ===== YOUR EXISTING CODE BELOW (keep as is) =====
if (pastPosts.length > 0) {
  learningContext += "\n=== LEARNING FROM PAST SUCCESSFUL POSTS ===\n\n";
  learningContext += "Below are previously approved posts. Learn from their tone, structure, and clarity:\n\n";

  pastPosts.forEach((post, index) => {
    learningContext += `${index + 1}. Platform: ${post.json.platform}\n`;
    learningContext += `   Content: ${post.json.content}\n`;
    learningContext += `   Approved At: ${post.json.approved_at}\n\n`;
  });
} else {
  learningContext += "\n(No prior approved posts available yet.)\n";
}

// Return as a single item for the AI node
return [
  {
    json: {
      learning_context: learningContext,
      // Pass through enriched context
      enriched_context: enrichedContext
    }
  }
];

// Get all approved posts from previous node
const history = $input.all();

let learningContext = "";

if (history.length > 0) {
  learningContext += "\n=== LEARNING FROM PAST SUCCESSFUL POSTS ===\n\n";
  learningContext += "Below are previously approved posts. Learn from their tone, structure, and clarity:\n\n";

  history.forEach((post, index) => {
    learningContext += `${index + 1}. Platform: ${post.json.platform}\n`;
    learningContext += `   Content: ${post.json.content}\n`;
    learningContext += `   Approved At: ${post.json.approved_at}\n\n`;
  });
} else {
  learningContext += "\n(No prior approved posts available yet.)\n";
}

// Return as a single item for the AI node
return [
  {
    json: {
      learning_context: learningContext
    }
  }
];

// Get Ollama's response
const ollamaResponse = $input.first().json;

// Ollama returns the full response in the 'data' field as a string
// It contains multiple JSON objects, we need the last complete one
const responseData = ollamaResponse.data;

console.log('Raw Ollama data:', responseData);

// Split by newlines and find the one with "done":true
const lines = responseData.split('\n').filter(line => line.trim());
let fullResponse = '';

// Collect all the "response" fields to build the complete text
for (const line of lines) {
  try {
    const parsed = JSON.parse(line);
    if (parsed.response) {
      fullResponse += parsed.response;
    }
  } catch (e) {
    // Skip invalid JSON lines
  }
}

console.log('Full response text:', fullResponse);

// Now parse the JSON from the complete response
let contentData;
try {
  // The response should be a JSON object
  contentData = JSON.parse(fullResponse);
} catch (error) {
  console.error('Parsing error:', error);
  console.log('Response text:', fullResponse);

  // Fallback content
  contentData = {
    caption: "🩺 Managing diabetes starts with understanding your body. Monitor blood sugar regularly, eat balanced meals, and stay active. Small steps lead to big health improvements! 💪\n\n#DiabetesAwareness #HealthyLiving #BloodSugar #DiabetesCare #Wellness #HealthTips",
    image_prompt: "Professional medical illustration of diabetes management - person checking glucose monitor, surrounded by healthy foods and exercise equipment. Modern, clean design with teal colors. Empowering mood.",
    content_type: "Blood Sugar Management",
    key_message: "Consistent monitoring and healthy habits lead to better diabetes control"
  };
}

// Return formatted data
return {
  json: {
    content_id: `content_${Date.now()}`,
    caption: contentData.caption || "Default caption",
    image_prompt: contentData.image_prompt || "Default prompt",
    content_type: contentData.content_type || "General",
    key_message: contentData.key_message || "Stay healthy",
    timestamp: new Date().toISOString(),
    status: "pending_review",
    generation_source: "automatic_ollama"
  }
};

// =====================================================
// INPUTS
// =====================================================
const contentData = $('Parse Generated Content').first().json;

// Get the ComfyUI prompt that was sent
const comfyPrompt = $('Build ComfyUI JSON').first().json;

// DEBUG: Log what we're sending
console.log('=== COMFYUI PROMPT ===');
console.log(JSON.stringify(comfyPrompt, null, 2));

// Generate a random seed to avoid cache
if (comfyPrompt.prompt && comfyPrompt.prompt["3"] && comfyPrompt.prompt["3"].inputs) {
  comfyPrompt.prompt["3"].inputs.seed = Math.floor(Math.random() * 1000000000);
  console.log('Generated seed:', comfyPrompt.prompt["3"].inputs.seed);
}

// =====================================================
// QUEUE THE PROMPT TO COMFYUI AND GET prompt_id
// =====================================================
console.log('Queueing prompt to ComfyUI...');

let queueResponse;
try {
  queueResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://host.docker.internal:8188/prompt',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(comfyPrompt),
    json: true,
  });
} catch (error) {
  console.error('Failed to queue prompt:', error.message);
  throw new Error(`Failed to queue prompt to ComfyUI: ${error.message}`);
}

console.log('Queue response:', JSON.stringify(queueResponse, null, 2));

const promptId = queueResponse.prompt_id;

if (!promptId) {
  throw new Error('Missing prompt_id from ComfyUI response. Response: ' + JSON.stringify(queueResponse));
}

console.log(`✓ Successfully queued prompt ID: ${promptId}`);

// =====================================================
// POLL COMFYUI HISTORY (UP TO ~3 minutes)
// =====================================================
let history;
const maxAttempts = 90; // 3 minutes
let attemptCount = 0;

console.log('Starting to poll ComfyUI history...');

for (let i = 0; i < maxAttempts; i++) {
  attemptCount++;

  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `http://host.docker.internal:8188/history/${promptId}`,
      json: true,
    });

    history = res[promptId];

    if (i % 5 === 0) { // Log every 10 seconds
      console.log(`Poll attempt ${i + 1}/${maxAttempts}:`, history ? 'Got history' : 'No history yet');
    }

    // Check if we have outputs
    if (history && history.outputs && Object.keys(history.outputs).length > 0) {
      console.log('✓ Found outputs in history!');
      console.log('Outputs:', JSON.stringify(history.outputs, null, 2));
      break;
    }

    // Check if execution completed (even if cached)
    if (history && history.status && history.status.completed) {
      console.log('✓ Execution marked as completed');
      break;
    }

    // Check for errors
    if (history && history.status && history.status.status_str) {
      console.log('Status:', history.status.status_str);
    }

    // wait 2 seconds
    await new Promise(r => setTimeout(r, 2000));

  } catch (error) {
    console.error(`Polling attempt ${i + 1} failed:`, error.message);
  }
}

if (!history) {
  throw new Error(`ComfyUI never returned history after ${attemptCount} attempts (${attemptCount * 2} seconds) for prompt_id: ${promptId}. 

Please check:
1. ComfyUI console at http://host.docker.internal:8188
2. Look for error messages in ComfyUI terminal
3. Verify the model file exists: v1-5-pruned-emaonly.safetensors`);
}

console.log('Final history object:', JSON.stringify(history, null, 2));

// =====================================================
// FIND IMAGE OUTPUT
// =====================================================
let imageEntry = null;

console.log('Looking for image in outputs...');

// First, try to get from outputs (non-cached execution)
if (history.outputs && Object.keys(history.outputs).length > 0) {
  console.log('Checking outputs nodes:', Object.keys(history.outputs));

  for (const nodeId of Object.keys(history.outputs)) {
    const output = history.outputs[nodeId];
    console.log(`Node ${nodeId}:`, output);

    if (output.images && output.images.length > 0) {
      imageEntry = output.images[0];
      console.log('✓ Found image in node', nodeId, ':', imageEntry.filename);
      break;
    }
  }
}

// If not found in outputs, try alternate method
if (!imageEntry) {
  console.log('No image in outputs, trying to construct filename...');

  // Try to find SaveImage node in prompt
  let filenamePrefix = "ComfyUI";

  if (history.prompt) {
    console.log('Prompt nodes:', Object.keys(history.prompt[2] || {}));

    // Look for SaveImage node (usually node 9)
    for (const nodeId of Object.keys(history.prompt[2] || {})) {
      const node = history.prompt[2][nodeId];
      if (node.class_type === "SaveImage" && node.inputs && node.inputs.filename_prefix) {
        filenamePrefix = node.inputs.filename_prefix;
        console.log('Found filename_prefix:', filenamePrefix);
        break;
      }
    }
  }

  const possibleFilenames = [
    `${filenamePrefix}_00001_.png`,
    `${filenamePrefix}_00000_.png`,
    `${filenamePrefix}.png`,
    `ComfyUI_00001_.png`,
  ];

  console.log('Trying possible filenames:', possibleFilenames);

  for (const filename of possibleFilenames) {
    try {
      const testUrl = `http://host.docker.internal:8188/view?filename=${filename}&type=output&subfolder=`;
      console.log('Testing URL:', testUrl);

      await this.helpers.httpRequest({
        method: 'GET',
        url: testUrl,
        encoding: null,
      });

      imageEntry = {
        filename: filename,
        subfolder: "",
        type: "output"
      };
      console.log('✓ Found image file:', filename);
      break;
    } catch (e) {
      console.log(`× File ${filename} not found`);
      continue;
    }
  }
}

if (!imageEntry) {
  throw new Error('No image found after exhaustive search. Full history: ' + JSON.stringify(history, null, 2));
}

// =====================================================
// BUILD IMAGE URL
// =====================================================
const imageUrl =
  `http://host.docker.internal:8188/view` +
  `?filename=${imageEntry.filename}` +
  `&subfolder=${imageEntry.subfolder || ''}` +
  `&type=${imageEntry.type || 'output'}`;

console.log('Final image URL:', imageUrl);

// =====================================================
// DOWNLOAD IMAGE
// =====================================================
console.log('Downloading image...');

const imageResponse = await this.helpers.httpRequest({
  method: 'GET',
  url: imageUrl,
  encoding: 'arraybuffer',
  returnFullResponse: true,
});

// Get the actual buffer data
const imageBuffer = Buffer.from(imageResponse.body);

console.log('✓ Image downloaded, size:', imageBuffer.length, 'bytes');

// =====================================================
// RETURN DATA WITH PROPER BINARY FORMAT
// =====================================================
return [
  {
    json: {
      content_id: contentData.content_id,
      caption: contentData.caption,
      image_prompt: contentData.image_prompt,
      content_type: contentData.content_type,
      key_message: contentData.key_message,
      timestamp: contentData.timestamp,
      status: 'ready_for_review',
      media_type: 'image',
      generation_source: contentData.generation_source,
      prompt_id: promptId,
    },
    binary: {
      image: {
        data: imageBuffer.toString('base64'),
        mimeType: 'image/png',
        fileName: 'diabetes_awareness.png',
      }
    }
  }
];

