// Planning Loop: Analyze task and create execution plan
const userMessage = $input.first().json.user_message;
const conversationHistory = $input.all()[1]?.json || [];
const knowledge = $input.all()[2]?.json || [];

// Determine task complexity
function analyzeTask(message) {
  const complexityIndicators = {
    simple: ['what', 'who', 'when', 'is', 'define'],
    medium: ['how', 'why', 'explain', 'compare', 'list'],
    complex: ['create', 'design', 'plan', 'strategy', 'analyze', 'generate', 'prescribe', 'diagnose', 'recommend treatment']
  };

  const lowerMessage = message.toLowerCase();

  if (complexityIndicators.complex.some(word => lowerMessage.includes(word))) {
    return 'complex';
  } else if (complexityIndicators.medium.some(word => lowerMessage.includes(word))) {
    return 'medium';
  }
  return 'simple';
}

// Create execution plan
function createPlan(message, complexity) {
  const plans = {
    simple: {
      steps: ['retrieve_knowledge', 'generate_response'],
      requiresApproval: false,
      estimatedTime: 'instant'
    },
    medium: {
      steps: ['retrieve_knowledge', 'analyze_context', 'generate_response', 'validate'],
      requiresApproval: false,
      estimatedTime: '5-10 seconds'
    },
    complex: {
      steps: ['retrieve_knowledge', 'analyze_context', 'create_subtasks', 'execute_subtasks', 'synthesize', 'validate', 'request_approval'],
      requiresApproval: true,
      estimatedTime: '30+ seconds'
    }
  };

  return plans[complexity];
}

const complexity = analyzeTask(userMessage);
const plan = createPlan(userMessage, complexity);

// Get original input data
const originalData = $input.first().json;

return {
  json: {
    ...originalData,
    user_message: userMessage,
    complexity: complexity,
    plan: plan,
    conversation_history: conversationHistory,
    knowledge_base: knowledge,
    timestamp: new Date().toISOString(),
    requires_governance: plan.requiresApproval
  }
};

// Governance: Apply content policies and safety checks
const data = $input.first().json;

// Define governance rules
const governanceRules = {
  contentPolicies: {
    noBrandViolations: true,
    noMedicalClaims: true,
    noOffensiveContent: true,
    requireDisclaimer: ['medical', 'advice', 'diagnosis']
  },
  safetyChecks: {
    maxContentLength: 5000,
    requireCitations: true,
    blockSensitiveTopics: ['personal health data', 'unapproved treatments']
  },
  approvalThresholds: {
    highRisk: ['prescription', 'prescribe', 'emergency', 'crisis', 'diagnose', 'diagnosis'],
    mediumRisk: ['treatment', 'symptoms', 'medication', 'medicine'],
    lowRisk: ['general', 'lifestyle', 'prevention', 'diet']
  }
};

// Check for violations
function checkGovernance(message, rules) {
  const violations = [];
  const warnings = [];
  let riskLevel = 'low';

  const lowerMessage = message.toLowerCase();

  // Check high risk keywords
  if (rules.approvalThresholds.highRisk.some(word => lowerMessage.includes(word))) {
    riskLevel = 'high';
    warnings.push('High-risk medical content detected');
  }

  // Check medium risk keywords
  if (rules.approvalThresholds.mediumRisk.some(word => lowerMessage.includes(word))) {
    riskLevel = riskLevel === 'high' ? 'high' : 'medium';
    warnings.push('Medical content requires disclaimer');
  }

  // Check blocked topics
  if (rules.safetyChecks.blockSensitiveTopics.some(topic => lowerMessage.includes(topic))) {
    violations.push('Sensitive topic detected - requires human review');
  }

  return {
    passed: violations.length === 0,
    riskLevel: riskLevel,
    violations: violations,
    warnings: warnings,
    requiresDisclaimer: warnings.length > 0
  };
}

const governanceCheck = checkGovernance(data.user_message, governanceRules);

return {
  json: {
    ...data,
    governance: {
      status: governanceCheck.passed ? 'approved' : 'requires_review',
      riskLevel: governanceCheck.riskLevel,
      violations: governanceCheck.violations,
      warnings: governanceCheck.warnings,
      requiresDisclaimer: governanceCheck.requiresDisclaimer,
      checkedAt: new Date().toISOString()
    },
    canProceed: governanceCheck.passed
  }
};

// Context Enrichment: Prepare enriched context for AI
const input = $input.first().json;

// Build enriched context
const enrichedContext = {
  current_query: input.user_message,
  conversation_summary: Array.isArray(input.conversation_history) 
    ? input.conversation_history.slice(-5).map(msg => 
        `${msg.role}: ${msg.content}`
      ).join('\n') 
    : 'No previous conversation',
  relevant_knowledge: Array.isArray(input.knowledge_base) 
    ? input.knowledge_base.map(k => 
        `[${k.topic}] ${k.content}`
      ).join('\n\n') 
    : 'No specific knowledge found',
  execution_plan: input.plan,
  governance_status: input.governance || { status: 'not_checked' },
  system_instructions: `You are a professional diabetes care assistant. 
Your role is to:
- Provide accurate, evidence-based information
- Maintain a supportive and empathetic tone
- Always include appropriate disclaimers for medical content
- Follow brand guidelines and content policies
- Act as a knowledgeable employee, not just a chatbot

Current task complexity: ${input.complexity}
Governance status: ${input.governance?.status || 'not checked'}`
};

return {
  json: {
    ...input,
    enriched_context: enrichedContext,
    ready_for_ai: true
  }
};
